import api from "./axios";

// LOGIN
export const login = async (email: string, password: string) => {
  const res = await api.post("/auth/login", { email, password });
  return res.data;
};

// CURRENT USER
export const getCurrentUser = async () => {
  const res = await api.get("/auth/me");
  return res.data;
};

// REGISTER CUSTOMER
export const registerCustomer = (data: any) =>
  api.post("/auth/register/customer", data);

// OWNER STEP 1
export const registerOwnerStep1 = (data: any) =>
  api.post("/auth/register/owner/step1", data);

// OWNER STEP 2
export const registerOwnerStep2 = (data: any) =>
  api.post("/auth/register/owner/step2", data);

// OWNER STEP 3 — UPLOAD DOCS
export const registerOwnerStep3 = async (userId: number, files: any) => {
  const form = new FormData();

  form.append("userId", userId.toString());
  form.append("license", files.businessLicense);
  form.append("id_front", files.idCardFront);
  form.append("id_back", files.idCardBack);

  return api.post("/auth/register/owner/step3", form, {
    headers: { "Content-Type": "multipart/form-data" },
  });
};
